INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (3, 5, 'Team_5_302', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 4.4', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'RECRUITING', FALSE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2025-12-22 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (4, 5, 'Team_5_398', '분산 환경 티켓팅 트래픽 처리 플랫폼 Ticket-Catch 4.0', 'SYSTEM', '대규모 트래픽이 몰리는 티켓팅 상황을 분산 시스템으로 해결한 MSA 아키텍처 이벤트 기반 예매 서버', 'COMPLETED', FALSE, '# 티켓팅 분산 시스템 Ticket-Catch 🎫\n\n## 🏗 프로젝트 목표\n유명 아이돌 콘서트나 명절 기차표 예매처럼 특정 순간에 트래픽이 수백 배로 폭증하는 상황에서도, 메인 서버의 병목현상을 막고 사용자 대기열을 순차적으로 안전하게 처리할 수 있는 아키텍처 설계 및 구현을 목표로 합니다.\n\n## ⚙️ 시스템 아키텍처 특장점\n- 인증, 결제, 예매, 대기열 서비스로 완벽히 분리된 마이크로서비스 아키텍처(MSA) 결합\n- 비동기 이벤트 기반(Event-Driven) 통신을 위한 Message Queue 인프라 활용\n\n## 🛠 기술 및 인프라\n- **Backend**: Spring Boot, Spring Cloud, Spring Security\n- **Message Broker**: Apache Kafka (티켓 발급 및 포인트 차감 처리)\n- **Cache/DB**: Redis (대기열 토큰 관리, 잔여 좌석 캐싱), MySQL(Replication)\n- **DevOps**: Docker, Kubernetes, Prometheus, Grafana\n\n## 🔥 성능 최적화 경험\n- **대기열 토큰 시스템**: Redis의 Sorted Set을 활용하여 초당 10만 건 이상의 접속자 접속 요청에 대해 O(log N)으로 공정한 진입 순번 발급\n- **분산 트랜잭션 (Saga Pattern)**: 티켓 예매 중 결제 실패 혹은 재고 부족 시 Kafka 이벤트를 롤백하는 Saga Choreography 패턴 적용\n- **부하 테스트 및 튜닝**: Jmeter를 활용한 Vuser 시뮬레이션으로 TPS 측정 후, WAS Thread Pool 조정과 쿼리 튜닝으로 최종 TPS 4,500 달성', '2025-12-28 10:58:41', '2026-03-11 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (5, 5, 'Team_5_550', '동네 기반 반려견 산책 메이트 매칭 앱 댕댕워크 v1.0', 'APP', '위치 기반으로 근처의 반려가족들과 산책 일정을 공유하고 함께 만날 수 있는 소셜 매칭 모바일 앱', 'CANCELED', TRUE, '# 댕댕워크 (DangDangWalk)\n\n## 🐶 서비스 개요\n반려견의 사회성 부족 고민, 이제 댕댕워크에서 동네 산책 크루를 만나 해결하세요! GPS 기반으로 우리 동네의 산책로를 공유하고 일정을 맞출 수 있는 소셜 네트워킹 크로스플랫폼 앱입니다.\n\n## 📱 주요 화면 및 기능\n- **주변 산책팟 조회**: 내 주변 2km 내에 있는 사용자 프로필 및 반려견 정보 지도 표시 (Google Maps API 활용)\n- **산책 크루 모집**: 날짜, 시간, 반려견 성향(소형견, 대형견, 사회성 등)에 맞춘 모집글 작성 및 수락 기능\n- **산책 기록 트래킹**: 산책한 동선과 소모 칼로리, 시간 등을 기록하여 통계 제공\n\n## ⚙️ 아키텍처 및 기술\n- **Client**: Flutter, Dart\n- **Server**: Node.js (Express), Socket.io (실시간 채팅)\n- **Database**: MongoDB (위치 데이터 처리에 적합한 Geospatial Index 활용)\n\n## 💡 주안점\n- 실시간 위치 공유 시 배터리 소모를 줄이기 위해 백그라운드 위치 업데이트 주기 최적화\n- REST API 설계 원칙을 준수하여 확장성 높은 서버 구조 설계', '2025-12-23 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (6, 6, 'Team_6_426', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 3.7', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'CANCELED', FALSE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2026-02-09 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (7, 7, 'Team_7_201', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 3.3', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'COMPLETED', FALSE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2026-03-04 10:58:41', '2026-03-12 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (8, 7, 'Team_7_193', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 1.7', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'RECRUITING', TRUE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2026-01-12 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (9, 8, 'Team_8_923', 'LLM 기반 모의면접 자동 피드백 서비스 Interview-GPT 4.7', 'AI', '구직자의 음성을 실시간 변환하고, LLM을 통해 꼬리질문과 답변 피드백을 제공하는 AI 면접관 플랫폼', 'IN_PROGRESS', TRUE, '# Interview-GPT 🤖\n\n## 🔍 기획 배경\n취업 준비생들이 면접 학원이나 스터디 없이도 언제든 실전 같은 면접을 경험할 수 있도록 돕고자 프롬프트 엔지니어링과 STT/TTS 기술을 결합하여 가상의 면접관을 구현했습니다.\n\n## 🎯 주요 기능\n- **맞춤형 질문 생성**: 이력서 데이터 파싱 및 직무 맞춤형 초기 면접 질문 자동 추출\n- **실시간 STT/TTS 대화**: 사용자의 음성을 텍스트로 변환 후, AI 면접관이 맥락에 맞는 꼬리질문 진행\n- **면접 리포트 발급**: 시선 처리, 목소리 크기, 답변의 논리성 등을 종합한 최종 피드백 리포트 제공\n\n## 🧠 기술 스택 - AI 파트\n- **LLM**: OpenAI GPT-4 API (프롬프트 튜닝, Few-shot 러닝 적용)\n- **Speech**: Whisper API (STT), Google Cloud TTS\n- **Vision**: MediaPipe (실시간 안면 및 시선 추적)\n- **Backend**: FastAPI, Python\n\n## 🚀 핵심 성과\n- 약 1,000건의 면접 Q&A 데이터를 활용한 프롬프트 최적화로 환각(Hallucination) 현상 방지\n- 프론트엔드와 AI 서버 간 WebSocket 통신을 통해 음성 처리 지연 시간(Latency) 1.5초 이내 방어', '2026-02-07 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (10, 8, 'Team_8_471', '분산 환경 티켓팅 트래픽 처리 플랫폼 Ticket-Catch 4.7', 'SYSTEM', '대규모 트래픽이 몰리는 티켓팅 상황을 분산 시스템으로 해결한 MSA 아키텍처 이벤트 기반 예매 서버', 'COMPLETED', FALSE, '# 티켓팅 분산 시스템 Ticket-Catch 🎫\n\n## 🏗 프로젝트 목표\n유명 아이돌 콘서트나 명절 기차표 예매처럼 특정 순간에 트래픽이 수백 배로 폭증하는 상황에서도, 메인 서버의 병목현상을 막고 사용자 대기열을 순차적으로 안전하게 처리할 수 있는 아키텍처 설계 및 구현을 목표로 합니다.\n\n## ⚙️ 시스템 아키텍처 특장점\n- 인증, 결제, 예매, 대기열 서비스로 완벽히 분리된 마이크로서비스 아키텍처(MSA) 결합\n- 비동기 이벤트 기반(Event-Driven) 통신을 위한 Message Queue 인프라 활용\n\n## 🛠 기술 및 인프라\n- **Backend**: Spring Boot, Spring Cloud, Spring Security\n- **Message Broker**: Apache Kafka (티켓 발급 및 포인트 차감 처리)\n- **Cache/DB**: Redis (대기열 토큰 관리, 잔여 좌석 캐싱), MySQL(Replication)\n- **DevOps**: Docker, Kubernetes, Prometheus, Grafana\n\n## 🔥 성능 최적화 경험\n- **대기열 토큰 시스템**: Redis의 Sorted Set을 활용하여 초당 10만 건 이상의 접속자 접속 요청에 대해 O(log N)으로 공정한 진입 순번 발급\n- **분산 트랜잭션 (Saga Pattern)**: 티켓 예매 중 결제 실패 혹은 재고 부족 시 Kafka 이벤트를 롤백하는 Saga Choreography 패턴 적용\n- **부하 테스트 및 튜닝**: Jmeter를 활용한 Vuser 시뮬레이션으로 TPS 측정 후, WAS Thread Pool 조정과 쿼리 튜닝으로 최종 TPS 4,500 달성', '2026-03-01 10:58:41', '2026-03-11 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (11, 9, 'Team_9_520', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 3.2', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'COMPLETED', FALSE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2025-12-20 10:58:41', '2026-03-08 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (12, 9, 'Team_9_912', '동네 기반 반려견 산책 메이트 매칭 앱 댕댕워크 v3.9', 'APP', '위치 기반으로 근처의 반려가족들과 산책 일정을 공유하고 함께 만날 수 있는 소셜 매칭 모바일 앱', 'IN_PROGRESS', TRUE, '# 댕댕워크 (DangDangWalk)\n\n## 🐶 서비스 개요\n반려견의 사회성 부족 고민, 이제 댕댕워크에서 동네 산책 크루를 만나 해결하세요! GPS 기반으로 우리 동네의 산책로를 공유하고 일정을 맞출 수 있는 소셜 네트워킹 크로스플랫폼 앱입니다.\n\n## 📱 주요 화면 및 기능\n- **주변 산책팟 조회**: 내 주변 2km 내에 있는 사용자 프로필 및 반려견 정보 지도 표시 (Google Maps API 활용)\n- **산책 크루 모집**: 날짜, 시간, 반려견 성향(소형견, 대형견, 사회성 등)에 맞춘 모집글 작성 및 수락 기능\n- **산책 기록 트래킹**: 산책한 동선과 소모 칼로리, 시간 등을 기록하여 통계 제공\n\n## ⚙️ 아키텍처 및 기술\n- **Client**: Flutter, Dart\n- **Server**: Node.js (Express), Socket.io (실시간 채팅)\n- **Database**: MongoDB (위치 데이터 처리에 적합한 Geospatial Index 활용)\n\n## 💡 주안점\n- 실시간 위치 공유 시 배터리 소모를 줄이기 위해 백그라운드 위치 업데이트 주기 최적화\n- REST API 설계 원칙을 준수하여 확장성 높은 서버 구조 설계', '2026-02-10 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (13, 10, 'Team_10_847', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 3.0', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'IN_PROGRESS', FALSE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2026-02-25 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (14, 10, 'Team_10_571', '실시간 협업 웹 플랫폼 Collabo v4.7', 'WEB', '웹소켓 지원으로 다중 사용자가 동시에 문서를 편집할 수 있는 팀 프로젝트 관리 툴입니다.', 'COMPLETED', FALSE, '# Collabo - 실시간 협업 웹 플랫폼\n\n## 💡 프로젝트 소개\n재택근무 및 비대면 환경의 증가로 실시간 협업의 중요성이 대두되었습니다. Collabo는 팀원들이 언제 어디서든 끊김 없이 소통하고 프로젝트를 관리할 수 있는 All-in-One 웹 서비스입니다.\n\n## 🚀 핵심 기능\n1. **실시간 문서 동시 편집**: 웹소켓을 통한 실시간 타이핑 공유 및 충돌 방지 로직 적용\n2. **드래그 앤 드롭 칸반 보드**: 직관적인 UI/UX로 업무 진행 상황(To Do, In Progress, Done) 관리\n3. **프로젝트 단위 그룹 채팅**: 업무 히스토리가 기록되는 스레드형 채팅 지원\n\n## 🛠 기술 스택\n- **Backend**: Spring Boot 3, Java 17, JPA, WebSocket(STOMP)\n- **Frontend**: React 18, TypeScript, TailwindCSS\n- **Database/Cache**: MySQL 8.x, Redis\n- **Infra**: AWS EC2, S3, RDS, GitHub Actions (CI/CD)\n\n## 🔥 성과 및 트러블 슈팅\n- 대용량 트래픽 대비: Ngrinder를 사용한 부하 테스트로 임계점 파악 및 병목 지점(채팅방 조회)에 분산 캐시 적용.\n- 응답 속도 개선: 쿼리 N+1 문제 해결을 통해 조회 성능 45% 향상.', '2026-01-04 10:58:41', '2026-03-12 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (15, 13, 'Team_13_557', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 4.2', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'CANCELED', TRUE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2026-02-01 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (16, 13, 'Team_13_505', '동네 기반 반려견 산책 메이트 매칭 앱 댕댕워크 v3.0', 'APP', '위치 기반으로 근처의 반려가족들과 산책 일정을 공유하고 함께 만날 수 있는 소셜 매칭 모바일 앱', 'CANCELED', FALSE, '# 댕댕워크 (DangDangWalk)\n\n## 🐶 서비스 개요\n반려견의 사회성 부족 고민, 이제 댕댕워크에서 동네 산책 크루를 만나 해결하세요! GPS 기반으로 우리 동네의 산책로를 공유하고 일정을 맞출 수 있는 소셜 네트워킹 크로스플랫폼 앱입니다.\n\n## 📱 주요 화면 및 기능\n- **주변 산책팟 조회**: 내 주변 2km 내에 있는 사용자 프로필 및 반려견 정보 지도 표시 (Google Maps API 활용)\n- **산책 크루 모집**: 날짜, 시간, 반려견 성향(소형견, 대형견, 사회성 등)에 맞춘 모집글 작성 및 수락 기능\n- **산책 기록 트래킹**: 산책한 동선과 소모 칼로리, 시간 등을 기록하여 통계 제공\n\n## ⚙️ 아키텍처 및 기술\n- **Client**: Flutter, Dart\n- **Server**: Node.js (Express), Socket.io (실시간 채팅)\n- **Database**: MongoDB (위치 데이터 처리에 적합한 Geospatial Index 활용)\n\n## 💡 주안점\n- 실시간 위치 공유 시 배터리 소모를 줄이기 위해 백그라운드 위치 업데이트 주기 최적화\n- REST API 설계 원칙을 준수하여 확장성 높은 서버 구조 설계', '2026-03-06 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (17, 13, 'Team_13_546', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 3.5', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'IN_PROGRESS', TRUE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2026-02-14 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (18, 14, 'Team_14_849', 'LLM 기반 모의면접 자동 피드백 서비스 Interview-GPT 4.2', 'AI', '구직자의 음성을 실시간 변환하고, LLM을 통해 꼬리질문과 답변 피드백을 제공하는 AI 면접관 플랫폼', 'RECRUITING', FALSE, '# Interview-GPT 🤖\n\n## 🔍 기획 배경\n취업 준비생들이 면접 학원이나 스터디 없이도 언제든 실전 같은 면접을 경험할 수 있도록 돕고자 프롬프트 엔지니어링과 STT/TTS 기술을 결합하여 가상의 면접관을 구현했습니다.\n\n## 🎯 주요 기능\n- **맞춤형 질문 생성**: 이력서 데이터 파싱 및 직무 맞춤형 초기 면접 질문 자동 추출\n- **실시간 STT/TTS 대화**: 사용자의 음성을 텍스트로 변환 후, AI 면접관이 맥락에 맞는 꼬리질문 진행\n- **면접 리포트 발급**: 시선 처리, 목소리 크기, 답변의 논리성 등을 종합한 최종 피드백 리포트 제공\n\n## 🧠 기술 스택 - AI 파트\n- **LLM**: OpenAI GPT-4 API (프롬프트 튜닝, Few-shot 러닝 적용)\n- **Speech**: Whisper API (STT), Google Cloud TTS\n- **Vision**: MediaPipe (실시간 안면 및 시선 추적)\n- **Backend**: FastAPI, Python\n\n## 🚀 핵심 성과\n- 약 1,000건의 면접 Q&A 데이터를 활용한 프롬프트 최적화로 환각(Hallucination) 현상 방지\n- 프론트엔드와 AI 서버 간 WebSocket 통신을 통해 음성 처리 지연 시간(Latency) 1.5초 이내 방어', '2025-12-19 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (19, 14, 'Team_14_526', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 3.6', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'IN_PROGRESS', TRUE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2026-01-09 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (20, 15, 'Team_15_699', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 3.0', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'IN_PROGRESS', FALSE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2026-01-12 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (21, 15, 'Team_15_273', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 2.9', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'IN_PROGRESS', FALSE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2026-01-06 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (22, 16, 'Team_16_402', '분산 환경 티켓팅 트래픽 처리 플랫폼 Ticket-Catch 4.2', 'SYSTEM', '대규모 트래픽이 몰리는 티켓팅 상황을 분산 시스템으로 해결한 MSA 아키텍처 이벤트 기반 예매 서버', 'IN_PROGRESS', FALSE, '# 티켓팅 분산 시스템 Ticket-Catch 🎫\n\n## 🏗 프로젝트 목표\n유명 아이돌 콘서트나 명절 기차표 예매처럼 특정 순간에 트래픽이 수백 배로 폭증하는 상황에서도, 메인 서버의 병목현상을 막고 사용자 대기열을 순차적으로 안전하게 처리할 수 있는 아키텍처 설계 및 구현을 목표로 합니다.\n\n## ⚙️ 시스템 아키텍처 특장점\n- 인증, 결제, 예매, 대기열 서비스로 완벽히 분리된 마이크로서비스 아키텍처(MSA) 결합\n- 비동기 이벤트 기반(Event-Driven) 통신을 위한 Message Queue 인프라 활용\n\n## 🛠 기술 및 인프라\n- **Backend**: Spring Boot, Spring Cloud, Spring Security\n- **Message Broker**: Apache Kafka (티켓 발급 및 포인트 차감 처리)\n- **Cache/DB**: Redis (대기열 토큰 관리, 잔여 좌석 캐싱), MySQL(Replication)\n- **DevOps**: Docker, Kubernetes, Prometheus, Grafana\n\n## 🔥 성능 최적화 경험\n- **대기열 토큰 시스템**: Redis의 Sorted Set을 활용하여 초당 10만 건 이상의 접속자 접속 요청에 대해 O(log N)으로 공정한 진입 순번 발급\n- **분산 트랜잭션 (Saga Pattern)**: 티켓 예매 중 결제 실패 혹은 재고 부족 시 Kafka 이벤트를 롤백하는 Saga Choreography 패턴 적용\n- **부하 테스트 및 튜닝**: Jmeter를 활용한 Vuser 시뮬레이션으로 TPS 측정 후, WAS Thread Pool 조정과 쿼리 튜닝으로 최종 TPS 4,500 달성', '2026-01-25 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (23, 17, 'Team_17_574', '실시간 협업 웹 플랫폼 Collabo v2.2', 'WEB', '웹소켓 지원으로 다중 사용자가 동시에 문서를 편집할 수 있는 팀 프로젝트 관리 툴입니다.', 'RECRUITING', FALSE, '# Collabo - 실시간 협업 웹 플랫폼\n\n## 💡 프로젝트 소개\n재택근무 및 비대면 환경의 증가로 실시간 협업의 중요성이 대두되었습니다. Collabo는 팀원들이 언제 어디서든 끊김 없이 소통하고 프로젝트를 관리할 수 있는 All-in-One 웹 서비스입니다.\n\n## 🚀 핵심 기능\n1. **실시간 문서 동시 편집**: 웹소켓을 통한 실시간 타이핑 공유 및 충돌 방지 로직 적용\n2. **드래그 앤 드롭 칸반 보드**: 직관적인 UI/UX로 업무 진행 상황(To Do, In Progress, Done) 관리\n3. **프로젝트 단위 그룹 채팅**: 업무 히스토리가 기록되는 스레드형 채팅 지원\n\n## 🛠 기술 스택\n- **Backend**: Spring Boot 3, Java 17, JPA, WebSocket(STOMP)\n- **Frontend**: React 18, TypeScript, TailwindCSS\n- **Database/Cache**: MySQL 8.x, Redis\n- **Infra**: AWS EC2, S3, RDS, GitHub Actions (CI/CD)\n\n## 🔥 성과 및 트러블 슈팅\n- 대용량 트래픽 대비: Ngrinder를 사용한 부하 테스트로 임계점 파악 및 병목 지점(채팅방 조회)에 분산 캐시 적용.\n- 응답 속도 개선: 쿼리 N+1 문제 해결을 통해 조회 성능 45% 향상.', '2026-02-11 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (24, 17, 'Team_17_485', '실시간 협업 웹 플랫폼 Collabo v3.1', 'WEB', '웹소켓 지원으로 다중 사용자가 동시에 문서를 편집할 수 있는 팀 프로젝트 관리 툴입니다.', 'RECRUITING', TRUE, '# Collabo - 실시간 협업 웹 플랫폼\n\n## 💡 프로젝트 소개\n재택근무 및 비대면 환경의 증가로 실시간 협업의 중요성이 대두되었습니다. Collabo는 팀원들이 언제 어디서든 끊김 없이 소통하고 프로젝트를 관리할 수 있는 All-in-One 웹 서비스입니다.\n\n## 🚀 핵심 기능\n1. **실시간 문서 동시 편집**: 웹소켓을 통한 실시간 타이핑 공유 및 충돌 방지 로직 적용\n2. **드래그 앤 드롭 칸반 보드**: 직관적인 UI/UX로 업무 진행 상황(To Do, In Progress, Done) 관리\n3. **프로젝트 단위 그룹 채팅**: 업무 히스토리가 기록되는 스레드형 채팅 지원\n\n## 🛠 기술 스택\n- **Backend**: Spring Boot 3, Java 17, JPA, WebSocket(STOMP)\n- **Frontend**: React 18, TypeScript, TailwindCSS\n- **Database/Cache**: MySQL 8.x, Redis\n- **Infra**: AWS EC2, S3, RDS, GitHub Actions (CI/CD)\n\n## 🔥 성과 및 트러블 슈팅\n- 대용량 트래픽 대비: Ngrinder를 사용한 부하 테스트로 임계점 파악 및 병목 지점(채팅방 조회)에 분산 캐시 적용.\n- 응답 속도 개선: 쿼리 N+1 문제 해결을 통해 조회 성능 45% 향상.', '2026-02-13 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (25, 17, 'Team_17_682', '실시간 협업 웹 플랫폼 Collabo v3.3', 'WEB', '웹소켓 지원으로 다중 사용자가 동시에 문서를 편집할 수 있는 팀 프로젝트 관리 툴입니다.', 'RECRUITING', TRUE, '# Collabo - 실시간 협업 웹 플랫폼\n\n## 💡 프로젝트 소개\n재택근무 및 비대면 환경의 증가로 실시간 협업의 중요성이 대두되었습니다. Collabo는 팀원들이 언제 어디서든 끊김 없이 소통하고 프로젝트를 관리할 수 있는 All-in-One 웹 서비스입니다.\n\n## 🚀 핵심 기능\n1. **실시간 문서 동시 편집**: 웹소켓을 통한 실시간 타이핑 공유 및 충돌 방지 로직 적용\n2. **드래그 앤 드롭 칸반 보드**: 직관적인 UI/UX로 업무 진행 상황(To Do, In Progress, Done) 관리\n3. **프로젝트 단위 그룹 채팅**: 업무 히스토리가 기록되는 스레드형 채팅 지원\n\n## 🛠 기술 스택\n- **Backend**: Spring Boot 3, Java 17, JPA, WebSocket(STOMP)\n- **Frontend**: React 18, TypeScript, TailwindCSS\n- **Database/Cache**: MySQL 8.x, Redis\n- **Infra**: AWS EC2, S3, RDS, GitHub Actions (CI/CD)\n\n## 🔥 성과 및 트러블 슈팅\n- 대용량 트래픽 대비: Ngrinder를 사용한 부하 테스트로 임계점 파악 및 병목 지점(채팅방 조회)에 분산 캐시 적용.\n- 응답 속도 개선: 쿼리 N+1 문제 해결을 통해 조회 성능 45% 향상.', '2026-02-15 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (26, 18, 'Team_18_160', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 4.8', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'RECRUITING', TRUE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2026-02-01 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (27, 19, 'Team_19_653', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 1.5', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'COMPLETED', FALSE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2026-01-12 10:58:41', '2026-03-10 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (28, 19, 'Team_19_379', '동네 기반 반려견 산책 메이트 매칭 앱 댕댕워크 v3.9', 'APP', '위치 기반으로 근처의 반려가족들과 산책 일정을 공유하고 함께 만날 수 있는 소셜 매칭 모바일 앱', 'IN_PROGRESS', TRUE, '# 댕댕워크 (DangDangWalk)\n\n## 🐶 서비스 개요\n반려견의 사회성 부족 고민, 이제 댕댕워크에서 동네 산책 크루를 만나 해결하세요! GPS 기반으로 우리 동네의 산책로를 공유하고 일정을 맞출 수 있는 소셜 네트워킹 크로스플랫폼 앱입니다.\n\n## 📱 주요 화면 및 기능\n- **주변 산책팟 조회**: 내 주변 2km 내에 있는 사용자 프로필 및 반려견 정보 지도 표시 (Google Maps API 활용)\n- **산책 크루 모집**: 날짜, 시간, 반려견 성향(소형견, 대형견, 사회성 등)에 맞춘 모집글 작성 및 수락 기능\n- **산책 기록 트래킹**: 산책한 동선과 소모 칼로리, 시간 등을 기록하여 통계 제공\n\n## ⚙️ 아키텍처 및 기술\n- **Client**: Flutter, Dart\n- **Server**: Node.js (Express), Socket.io (실시간 채팅)\n- **Database**: MongoDB (위치 데이터 처리에 적합한 Geospatial Index 활용)\n\n## 💡 주안점\n- 실시간 위치 공유 시 배터리 소모를 줄이기 위해 백그라운드 위치 업데이트 주기 최적화\n- REST API 설계 원칙을 준수하여 확장성 높은 서버 구조 설계', '2025-12-29 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (29, 20, 'Team_20_456', '실시간 협업 웹 플랫폼 Collabo v2.0', 'WEB', '웹소켓 지원으로 다중 사용자가 동시에 문서를 편집할 수 있는 팀 프로젝트 관리 툴입니다.', 'RECRUITING', FALSE, '# Collabo - 실시간 협업 웹 플랫폼\n\n## 💡 프로젝트 소개\n재택근무 및 비대면 환경의 증가로 실시간 협업의 중요성이 대두되었습니다. Collabo는 팀원들이 언제 어디서든 끊김 없이 소통하고 프로젝트를 관리할 수 있는 All-in-One 웹 서비스입니다.\n\n## 🚀 핵심 기능\n1. **실시간 문서 동시 편집**: 웹소켓을 통한 실시간 타이핑 공유 및 충돌 방지 로직 적용\n2. **드래그 앤 드롭 칸반 보드**: 직관적인 UI/UX로 업무 진행 상황(To Do, In Progress, Done) 관리\n3. **프로젝트 단위 그룹 채팅**: 업무 히스토리가 기록되는 스레드형 채팅 지원\n\n## 🛠 기술 스택\n- **Backend**: Spring Boot 3, Java 17, JPA, WebSocket(STOMP)\n- **Frontend**: React 18, TypeScript, TailwindCSS\n- **Database/Cache**: MySQL 8.x, Redis\n- **Infra**: AWS EC2, S3, RDS, GitHub Actions (CI/CD)\n\n## 🔥 성과 및 트러블 슈팅\n- 대용량 트래픽 대비: Ngrinder를 사용한 부하 테스트로 임계점 파악 및 병목 지점(채팅방 조회)에 분산 캐시 적용.\n- 응답 속도 개선: 쿼리 N+1 문제 해결을 통해 조회 성능 45% 향상.', '2026-02-04 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (30, 20, 'Team_20_867', '분산 환경 티켓팅 트래픽 처리 플랫폼 Ticket-Catch 2.8', 'SYSTEM', '대규모 트래픽이 몰리는 티켓팅 상황을 분산 시스템으로 해결한 MSA 아키텍처 이벤트 기반 예매 서버', 'IN_PROGRESS', TRUE, '# 티켓팅 분산 시스템 Ticket-Catch 🎫\n\n## 🏗 프로젝트 목표\n유명 아이돌 콘서트나 명절 기차표 예매처럼 특정 순간에 트래픽이 수백 배로 폭증하는 상황에서도, 메인 서버의 병목현상을 막고 사용자 대기열을 순차적으로 안전하게 처리할 수 있는 아키텍처 설계 및 구현을 목표로 합니다.\n\n## ⚙️ 시스템 아키텍처 특장점\n- 인증, 결제, 예매, 대기열 서비스로 완벽히 분리된 마이크로서비스 아키텍처(MSA) 결합\n- 비동기 이벤트 기반(Event-Driven) 통신을 위한 Message Queue 인프라 활용\n\n## 🛠 기술 및 인프라\n- **Backend**: Spring Boot, Spring Cloud, Spring Security\n- **Message Broker**: Apache Kafka (티켓 발급 및 포인트 차감 처리)\n- **Cache/DB**: Redis (대기열 토큰 관리, 잔여 좌석 캐싱), MySQL(Replication)\n- **DevOps**: Docker, Kubernetes, Prometheus, Grafana\n\n## 🔥 성능 최적화 경험\n- **대기열 토큰 시스템**: Redis의 Sorted Set을 활용하여 초당 10만 건 이상의 접속자 접속 요청에 대해 O(log N)으로 공정한 진입 순번 발급\n- **분산 트랜잭션 (Saga Pattern)**: 티켓 예매 중 결제 실패 혹은 재고 부족 시 Kafka 이벤트를 롤백하는 Saga Choreography 패턴 적용\n- **부하 테스트 및 튜닝**: Jmeter를 활용한 Vuser 시뮬레이션으로 TPS 측정 후, WAS Thread Pool 조정과 쿼리 튜닝으로 최종 TPS 4,500 달성', '2026-01-15 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (31, 20, 'Team_20_622', '분산 환경 티켓팅 트래픽 처리 플랫폼 Ticket-Catch 1.4', 'SYSTEM', '대규모 트래픽이 몰리는 티켓팅 상황을 분산 시스템으로 해결한 MSA 아키텍처 이벤트 기반 예매 서버', 'CANCELED', TRUE, '# 티켓팅 분산 시스템 Ticket-Catch 🎫\n\n## 🏗 프로젝트 목표\n유명 아이돌 콘서트나 명절 기차표 예매처럼 특정 순간에 트래픽이 수백 배로 폭증하는 상황에서도, 메인 서버의 병목현상을 막고 사용자 대기열을 순차적으로 안전하게 처리할 수 있는 아키텍처 설계 및 구현을 목표로 합니다.\n\n## ⚙️ 시스템 아키텍처 특장점\n- 인증, 결제, 예매, 대기열 서비스로 완벽히 분리된 마이크로서비스 아키텍처(MSA) 결합\n- 비동기 이벤트 기반(Event-Driven) 통신을 위한 Message Queue 인프라 활용\n\n## 🛠 기술 및 인프라\n- **Backend**: Spring Boot, Spring Cloud, Spring Security\n- **Message Broker**: Apache Kafka (티켓 발급 및 포인트 차감 처리)\n- **Cache/DB**: Redis (대기열 토큰 관리, 잔여 좌석 캐싱), MySQL(Replication)\n- **DevOps**: Docker, Kubernetes, Prometheus, Grafana\n\n## 🔥 성능 최적화 경험\n- **대기열 토큰 시스템**: Redis의 Sorted Set을 활용하여 초당 10만 건 이상의 접속자 접속 요청에 대해 O(log N)으로 공정한 진입 순번 발급\n- **분산 트랜잭션 (Saga Pattern)**: 티켓 예매 중 결제 실패 혹은 재고 부족 시 Kafka 이벤트를 롤백하는 Saga Choreography 패턴 적용\n- **부하 테스트 및 튜닝**: Jmeter를 활용한 Vuser 시뮬레이션으로 TPS 측정 후, WAS Thread Pool 조정과 쿼리 튜닝으로 최종 TPS 4,500 달성', '2026-02-23 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (32, 21, 'Team_21_871', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 1.0', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'RECRUITING', FALSE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2026-03-05 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (33, 21, 'Team_21_655', '동네 기반 반려견 산책 메이트 매칭 앱 댕댕워크 v3.9', 'APP', '위치 기반으로 근처의 반려가족들과 산책 일정을 공유하고 함께 만날 수 있는 소셜 매칭 모바일 앱', 'COMPLETED', FALSE, '# 댕댕워크 (DangDangWalk)\n\n## 🐶 서비스 개요\n반려견의 사회성 부족 고민, 이제 댕댕워크에서 동네 산책 크루를 만나 해결하세요! GPS 기반으로 우리 동네의 산책로를 공유하고 일정을 맞출 수 있는 소셜 네트워킹 크로스플랫폼 앱입니다.\n\n## 📱 주요 화면 및 기능\n- **주변 산책팟 조회**: 내 주변 2km 내에 있는 사용자 프로필 및 반려견 정보 지도 표시 (Google Maps API 활용)\n- **산책 크루 모집**: 날짜, 시간, 반려견 성향(소형견, 대형견, 사회성 등)에 맞춘 모집글 작성 및 수락 기능\n- **산책 기록 트래킹**: 산책한 동선과 소모 칼로리, 시간 등을 기록하여 통계 제공\n\n## ⚙️ 아키텍처 및 기술\n- **Client**: Flutter, Dart\n- **Server**: Node.js (Express), Socket.io (실시간 채팅)\n- **Database**: MongoDB (위치 데이터 처리에 적합한 Geospatial Index 활용)\n\n## 💡 주안점\n- 실시간 위치 공유 시 배터리 소모를 줄이기 위해 백그라운드 위치 업데이트 주기 최적화\n- REST API 설계 원칙을 준수하여 확장성 높은 서버 구조 설계', '2025-12-31 10:58:41', '2026-03-14 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (34, 21, 'Team_21_113', 'LLM 기반 모의면접 자동 피드백 서비스 Interview-GPT 2.9', 'AI', '구직자의 음성을 실시간 변환하고, LLM을 통해 꼬리질문과 답변 피드백을 제공하는 AI 면접관 플랫폼', 'IN_PROGRESS', TRUE, '# Interview-GPT 🤖\n\n## 🔍 기획 배경\n취업 준비생들이 면접 학원이나 스터디 없이도 언제든 실전 같은 면접을 경험할 수 있도록 돕고자 프롬프트 엔지니어링과 STT/TTS 기술을 결합하여 가상의 면접관을 구현했습니다.\n\n## 🎯 주요 기능\n- **맞춤형 질문 생성**: 이력서 데이터 파싱 및 직무 맞춤형 초기 면접 질문 자동 추출\n- **실시간 STT/TTS 대화**: 사용자의 음성을 텍스트로 변환 후, AI 면접관이 맥락에 맞는 꼬리질문 진행\n- **면접 리포트 발급**: 시선 처리, 목소리 크기, 답변의 논리성 등을 종합한 최종 피드백 리포트 제공\n\n## 🧠 기술 스택 - AI 파트\n- **LLM**: OpenAI GPT-4 API (프롬프트 튜닝, Few-shot 러닝 적용)\n- **Speech**: Whisper API (STT), Google Cloud TTS\n- **Vision**: MediaPipe (실시간 안면 및 시선 추적)\n- **Backend**: FastAPI, Python\n\n## 🚀 핵심 성과\n- 약 1,000건의 면접 Q&A 데이터를 활용한 프롬프트 최적화로 환각(Hallucination) 현상 방지\n- 프론트엔드와 AI 서버 간 WebSocket 통신을 통해 음성 처리 지연 시간(Latency) 1.5초 이내 방어', '2026-02-28 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (35, 22, 'Team_22_831', '2D 픽셀아트 생존 로그라이크 Dark-Dungeon 1.1', 'GAME', '절차적 맵 생성 시스템과 다양한 무기 조합의 재미를 내세운 2D 쿼터뷰 액션 하드코어 로그라이크', 'CANCELED', FALSE, '# Dark-Dungeon 🎮\n\n## 📖 게임 소개\n어둠에 잠긴 지하 던전을 탈출하기 위해 끊임없이 몰려오는 몬스터들과 함정을 극복해야 하는 2D 플랫포머 하드코어 액션 게임입니다. 죽으면 모든 것을 잃지만 경험은 남습니다.\n\n## ⚔️ 코어 메커니즘\n- **절차적 맵 생성 (Procedural Generation)**: Random Walk 알고리즘을 응용하여 매 판마다 완전히 다른 구조의 던전 생성\n- **시너지 시스템**: 30여 종의 무기와 패시브 유물들을 조합하여 자신만의 유니크한 공격 빌드 구성 가능\n- **다이나믹 픽셀 라이팅**: 2D 광원 효과를 극대화시켜 횃불, 마법 이펙트 등 동적인 빛에 따라 시야가 제약되는 시스템 연출\n\n## 🛠 개발 환경\n- **Engine**: Unity 2D (C#)\n- **Art**: Aseprite (에셋 100% 자체 제작)\n\n## 🔬 트러블 슈팅 포인트\n- 오브젝트 풀링(Object Pooling) 패턴을 적극 도입하여 수백 개의 몬스터와 투사체가 동시에 렌더링될 때의 가비지 컬렉션(GC) 스파이크 및 프레임 드랍 문제 완화\n- FSM(Finite State Machine) 디자인 패턴을 활용한 보스 몬스터의 정교한 공격 페이즈 구현', '2026-01-31 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (36, 22, 'Team_22_165', '서울시 심야 대중교통 노선 최적화 분석 파이프라인 1.3', 'DATA', '카드 승하차 데이터와 통신사 유동인구 데이터를 결합하여 심야 대중교통 최적 노선을 제안하는 데이터 분석 프로젝트', 'COMPLETED', TRUE, '# 서울시 심야 교통 노선 최적화 프레임워크 🚌\n\n## 📊 분석 개요\n심야 시간대 주요 번화가의 대중교통 사각지대 현상을 해소하기 위해, 서울시 공공데이터와 통신사 유동인구 데이터를 결합 분석하여 가장 경제적이고 효율적인 신규 심야 버스 노선을 도출하는 빅데이터 파이프라인 구축 프로젝트입니다.\n\n## 📈 파이프라인 아키텍처\n1. **Data Ingestion**: 공공데이터 포털 Open API 스케줄링 적재 (Airflow 처리)\n2. **Data Storage & Processing**: AWS S3 적재 -> Apache Spark 기반의 대용량 데이터 분산 정제 -> Data Warehouse 적재\n3. **Clustering 분석**: K-Means 클러스터링으로 주요 심야 인구 밀집 지역(Hotspot) 파악 및 노드화\n4. **Visualization**: Tableau를 활용한 최종 노선도 인사이트 대시보드 배포\n\n## 💻 기술 스택\n- Python, Pandas, Scikit-learn, PySpark\n- AWS (S3, EMR, Athena), Apache Airflow\n\n## 🏆 인사이트 도출 결론\n- 기존 심야버스 노선 대비 교통 소외지역의 대기 시간 평균 15% 단축 모델 도출\n- 강남-신림, 홍대-이태원 구간 등 주요 취약 구간의 심야 배차 간격 조정에 대한 통계적 근거 확보 체계 구축', '2025-12-13 10:58:41', '2026-03-15 10:58:41');
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (37, 22, 'Team_22_133', '실시간 협업 웹 플랫폼 Collabo v2.3', 'WEB', '웹소켓 지원으로 다중 사용자가 동시에 문서를 편집할 수 있는 팀 프로젝트 관리 툴입니다.', 'IN_PROGRESS', TRUE, '# Collabo - 실시간 협업 웹 플랫폼\n\n## 💡 프로젝트 소개\n재택근무 및 비대면 환경의 증가로 실시간 협업의 중요성이 대두되었습니다. Collabo는 팀원들이 언제 어디서든 끊김 없이 소통하고 프로젝트를 관리할 수 있는 All-in-One 웹 서비스입니다.\n\n## 🚀 핵심 기능\n1. **실시간 문서 동시 편집**: 웹소켓을 통한 실시간 타이핑 공유 및 충돌 방지 로직 적용\n2. **드래그 앤 드롭 칸반 보드**: 직관적인 UI/UX로 업무 진행 상황(To Do, In Progress, Done) 관리\n3. **프로젝트 단위 그룹 채팅**: 업무 히스토리가 기록되는 스레드형 채팅 지원\n\n## 🛠 기술 스택\n- **Backend**: Spring Boot 3, Java 17, JPA, WebSocket(STOMP)\n- **Frontend**: React 18, TypeScript, TailwindCSS\n- **Database/Cache**: MySQL 8.x, Redis\n- **Infra**: AWS EC2, S3, RDS, GitHub Actions (CI/CD)\n\n## 🔥 성과 및 트러블 슈팅\n- 대용량 트래픽 대비: Ngrinder를 사용한 부하 테스트로 임계점 파악 및 병목 지점(채팅방 조회)에 분산 캐시 적용.\n- 응답 속도 개선: 쿼리 N+1 문제 해결을 통해 조회 성능 45% 향상.', '2026-01-24 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (38, 24, 'Team_24_518', 'LLM 기반 모의면접 자동 피드백 서비스 Interview-GPT 3.7', 'AI', '구직자의 음성을 실시간 변환하고, LLM을 통해 꼬리질문과 답변 피드백을 제공하는 AI 면접관 플랫폼', 'IN_PROGRESS', FALSE, '# Interview-GPT 🤖\n\n## 🔍 기획 배경\n취업 준비생들이 면접 학원이나 스터디 없이도 언제든 실전 같은 면접을 경험할 수 있도록 돕고자 프롬프트 엔지니어링과 STT/TTS 기술을 결합하여 가상의 면접관을 구현했습니다.\n\n## 🎯 주요 기능\n- **맞춤형 질문 생성**: 이력서 데이터 파싱 및 직무 맞춤형 초기 면접 질문 자동 추출\n- **실시간 STT/TTS 대화**: 사용자의 음성을 텍스트로 변환 후, AI 면접관이 맥락에 맞는 꼬리질문 진행\n- **면접 리포트 발급**: 시선 처리, 목소리 크기, 답변의 논리성 등을 종합한 최종 피드백 리포트 제공\n\n## 🧠 기술 스택 - AI 파트\n- **LLM**: OpenAI GPT-4 API (프롬프트 튜닝, Few-shot 러닝 적용)\n- **Speech**: Whisper API (STT), Google Cloud TTS\n- **Vision**: MediaPipe (실시간 안면 및 시선 추적)\n- **Backend**: FastAPI, Python\n\n## 🚀 핵심 성과\n- 약 1,000건의 면접 Q&A 데이터를 활용한 프롬프트 최적화로 환각(Hallucination) 현상 방지\n- 프론트엔드와 AI 서버 간 WebSocket 통신을 통해 음성 처리 지연 시간(Latency) 1.5초 이내 방어', '2026-03-04 10:58:41', NULL);
INSERT INTO projects (project_id, leader_id, team_name, title, domain, description, status, is_public, readme, created_at, finished_at) VALUES (39, 25, 'Team_25_677', '동네 기반 반려견 산책 메이트 매칭 앱 댕댕워크 v4.2', 'APP', '위치 기반으로 근처의 반려가족들과 산책 일정을 공유하고 함께 만날 수 있는 소셜 매칭 모바일 앱', 'IN_PROGRESS', FALSE, '# 댕댕워크 (DangDangWalk)\n\n## 🐶 서비스 개요\n반려견의 사회성 부족 고민, 이제 댕댕워크에서 동네 산책 크루를 만나 해결하세요! GPS 기반으로 우리 동네의 산책로를 공유하고 일정을 맞출 수 있는 소셜 네트워킹 크로스플랫폼 앱입니다.\n\n## 📱 주요 화면 및 기능\n- **주변 산책팟 조회**: 내 주변 2km 내에 있는 사용자 프로필 및 반려견 정보 지도 표시 (Google Maps API 활용)\n- **산책 크루 모집**: 날짜, 시간, 반려견 성향(소형견, 대형견, 사회성 등)에 맞춘 모집글 작성 및 수락 기능\n- **산책 기록 트래킹**: 산책한 동선과 소모 칼로리, 시간 등을 기록하여 통계 제공\n\n## ⚙️ 아키텍처 및 기술\n- **Client**: Flutter, Dart\n- **Server**: Node.js (Express), Socket.io (실시간 채팅)\n- **Database**: MongoDB (위치 데이터 처리에 적합한 Geospatial Index 활용)\n\n## 💡 주안점\n- 실시간 위치 공유 시 배터리 소모를 줄이기 위해 백그라운드 위치 업데이트 주기 최적화\n- REST API 설계 원칙을 준수하여 확장성 높은 서버 구조 설계', '2025-12-09 10:58:41', NULL);
